import re
chaps = ["Cohomology_SheafCompose","Cohomology_StructureSheafAb","Cohomology_StructureSheafModuleK","Genus","Picard_FGAPicRepresentability","Picard_IdentityComponent"]
def strip_comments(t):
    return re.sub(r'(?<!\\)%.*', '', t)
labels=set(); refs=set(); uses=set()
for c in chaps:
    t=strip_comments(open(c+'.tex').read())
    labels |= set(re.findall(r'\\label\{([^}]*)\}', t))
    for m in re.findall(r'\\(?:cref|Cref|ref|eqref)\{([^}]*)\}', t):
        refs |= set(x.strip() for x in m.split(','))
    for m in re.findall(r'\\uses\{([^}]*)\}', t):
        uses |= set(x.strip() for x in m.split(','))
print("DANGLING refs:", sorted(refs - labels))
print("DANGLING uses:", sorted(uses - labels))
EOF

