import re, glob
DANGLING = ['chap:AbelJacobi','chap:Albanese_AlbaneseUP','chap:Cohomology_MayerVietoris','chap:Picard_LineBundlePullback','chap:Picard_QuotScheme','chap:Picard_RelPicFunctor','chap:Picard_RelativeSpec','def:hilbert_polynomial','def:line_bundle_on_product','def:rel_pic_sharp','lem:cech_flat_base_change','thm:pullback_natural','thm:quot_representable','thm:relative_pic_quotient_well_defined']
# demote \cref/\Cref/\ref/\eqref{X} -> \texttt{X} ONLY when every target in the braces is dangling;
# mixed-target crefs are split manually if found (report them).
pat = re.compile(r'\\(cref|Cref|ref|eqref)\{([^}]*)\}')
for f in glob.glob('*.tex'):
    t = open(f).read()
    changed = False
    def repl(m):
        global changed
        targets = [x.strip() for x in m.group(2).split(',')]
        if all(x in DANGLING for x in targets):
            changed = True
            return '\\texttt{' + m.group(2).replace('_', r'\_') + '}'
        if any(x in DANGLING for x in targets):
            print('MIXED', f, m.group(0))
        return m.group(0)
    t2 = pat.sub(repl, t)
    if changed:
        open(f, 'w').write(t2)
        print('demoted in', f)
# re-check
def strip(t): return re.sub(r'(?<!\\)%.*','',t)
labels=set(); refs=set()
for f in glob.glob('*.tex'):
    t=strip(open(f).read())
    labels|=set(re.findall(r'\\label\{([^}]*)\}',t))
    for m in re.findall(r'\\(?:cref|Cref|ref|eqref)\{([^}]*)\}',t):
        refs|=set(x.strip() for x in m.split(','))
print("remaining dangling refs:", sorted(refs-labels))
EOF
